extension WebViewController: WKScriptMessageHandler {
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        switch message.name {
        case "camera":
            handleCameraRequest(message: message)
        case "pushNotifications":
            handlePushNotificationRequest(message: message)
        case "inAppPurchase":
            handleInAppPurchaseRequest(message: message)
        case "native":
            handleNativeRequest(message: message)
        default:
            break
        }
    }
    
    private func handleCameraRequest(message: WKScriptMessage) {
        guard let body = message.body as? [String: Any],
              let action = body["action"] as? String else {
            sendResponse(callbackId: nil, success: false, data: ["error": "Invalid camera request"])
            return
        }
        
        let callbackId = body["callbackId"] as? String
        
        switch action {
        case "takePicture":
            presentImagePicker(sourceType: .camera, callbackId: callbackId)
        case "selectFromGallery":
            presentImagePicker(sourceType: .photoLibrary, callbackId: callbackId)
        default:
            sendResponse(callbackId: callbackId, success: false, data: ["error": "Unknown camera action"])
        }
    }
    
    private func presentImagePicker(sourceType: UIImagePickerController.SourceType, callbackId: String?) {
        guard UIImagePickerController.isSourceTypeAvailable(sourceType) else {
            sendResponse(callbackId: callbackId, success: false, data: ["error": "Source type not available"])
            return
        }
        
        let picker = UIImagePickerController()
        picker.sourceType = sourceType
        picker.delegate = self
        picker.allowsEditing = true
        
        if let callbackId = callbackId {
            picker.accessibilityHint = callbackId
        }
        
        present(picker, animated: true)
    }
    
    private func handlePushNotificationRequest(message: WKScriptMessage) {
        guard let body = message.body as? [String: Any],
              let action = body["action"] as? String else {
            sendResponse(callbackId: nil, success: false, data: ["error": "Invalid notification request"])
            return
        }
        
        let callbackId = body["callbackId"] as? String
        
        switch action {
        case "requestPermission":
            requestNotificationPermission(callbackId: callbackId)
        case "getToken":
            getDeviceToken(callbackId: callbackId)
        case "scheduleLocal":
            if let title = body["title"] as? String,
               let body = body["body"] as? String {
                scheduleLocalNotification(title: title, body: body, callbackId: callbackId)
            }
        default:
            sendResponse(callbackId: callbackId, success: false, data: ["error": "Unknown notification action"])
        }
    }
    
    private func requestNotificationPermission(callbackId: String?) {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { granted, error in
            DispatchQueue.main.async {
                if let error = error {
                    self.sendResponse(callbackId: callbackId, success: false, data: ["error": error.localizedDescription])
                } else {
                    self.sendResponse(callbackId: callbackId, success: true, data: ["granted": granted])
                    if granted {
                        UIApplication.shared.registerForRemoteNotifications()
                    }
                }
            }
        }
    }
    
    private func getDeviceToken(callbackId: String?) {
        if let token = UserDefaults.standard.string(forKey: "deviceToken") {
            sendResponse(callbackId: callbackId, success: true, data: ["token": token])
        } else {
            sendResponse(callbackId: callbackId, success: false, data: ["error": "No device token available"])
        }
    }
    
    private func scheduleLocalNotification(title: String, body: String, callbackId: String?) {
        let content = UNMutableNotificationContent()
        content.title = title
        content.body = body
        content.sound = .default
        
        let trigger = UNTimeIntervalNotificationTrigger(timeInterval: 1, repeats: false)
        let request = UNNotificationRequest(identifier: UUID().uuidString, content: content, trigger: trigger)
        
        UNUserNotificationCenter.current().add(request) { error in
            DispatchQueue.main.async {
                if let error = error {
                    self.sendResponse(callbackId: callbackId, success: false, data: ["error": error.localizedDescription])
                } else {
                    self.sendResponse(callbackId: callbackId, success: true, data: [:])
                }
            }
        }
    }
    
    private func handleInAppPurchaseRequest(message: WKScriptMessage) {
        guard let body = message.body as? [String: Any],
              let action = body["action"] as? String else {
            sendResponse(callbackId: nil, success: false, data: ["error": "Invalid IAP request"])
            return
        }
        
        let callbackId = body["callbackId"] as? String
        
        switch action {
        case "purchase":
            if let productId = body["productId"] as? String {
                purchaseProduct(productId: productId, callbackId: callbackId)
            }
        case "restore":
            restorePurchases(callbackId: callbackId)
        case "getProducts":
            if let productIds = body["productIds"] as? [String] {
                fetchProducts(productIds: productIds, callbackId: callbackId)
            }
        default:
            sendResponse(callbackId: callbackId, success: false, data: ["error": "Unknown IAP action"])
        }
    }
    
    private func purchaseProduct(productId: String, callbackId: String?) {
        InAppPurchaseManager.shared.purchase(productId: productId) { success, error in
            if success {
                self.sendResponse(callbackId: callbackId, success: true, data: ["productId": productId])
            } else {
                self.sendResponse(callbackId: callbackId, success: false, data: ["error": error ?? "Purchase failed"])
            }
        }
    }
    
    private func restorePurchases(callbackId: String?) {
        InAppPurchaseManager.shared.restorePurchases { success, error in
            if success {
                self.sendResponse(callbackId: callbackId, success: true, data: [:])
            } else {
                self.sendResponse(callbackId: callbackId, success: false, data: ["error": error ?? "Restore failed"])
            }
        }
    }
    
    private func fetchProducts(productIds: [String], callbackId: String?) {
        InAppPurchaseManager.shared.fetchProducts(productIds: productIds) { products, error in
            if let products = products {
                let productsData = products.map { product in
                    return [
                        "productId": product.productIdentifier,
                        "title": product.localizedTitle,
                        "description": product.localizedDescription,
                        "price": product.price.stringValue,
                        "priceLocale": product.priceLocale.currencyCode ?? ""
                    ]
                }
                self.sendResponse(callbackId: callbackId, success: true, data: ["products": productsData])
            } else {
                self.sendResponse(callbackId: callbackId, success: false, data: ["error": error ?? "Failed to fetch products"])
            }
        }
    }
    
    private func handleNativeRequest(message: WKScriptMessage) {
        guard let body = message.body as? [String: Any],
              let action = body["action"] as? String else {
            sendResponse(callbackId: nil, success: false, data: ["error": "Invalid native request"])
            return
        }
        
        let callbackId = body["callbackId"] as? String
        
        switch action {
        case "getDeviceInfo":
            let deviceInfo: [String: Any] = [
                "platform": "iOS",
                "version": UIDevice.current.systemVersion,
                "model": UIDevice.current.model,
                "appVersion": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? ""
            ]
            sendResponse(callbackId: callbackId, success: true, data: deviceInfo)
        case "share":
            if let text = body["text"] as? String {
                shareContent(text: text, url: body["url"] as? String, callbackId: callbackId)
            }
        case "vibrate":
            UIImpactFeedbackGenerator(style: .medium).impactOccurred()
            sendResponse(callbackId: callbackId, success: true, data: [:])
        default:
            sendResponse(callbackId: callbackId, success: false, data: ["error": "Unknown native action"])
        }
    }
    
    private func shareContent(text: String, url: String?, callbackId: String?) {
        var items: [Any] = [text]
        if let urlString = url, let shareURL = URL(string: urlString) {
            items.append(shareURL)
        }
        
        let activityVC = UIActivityViewController(activityItems: items, applicationActivities: nil)
        activityVC.completionWithItemsHandler = { _, completed, _, error in
            if let error = error {
                self.sendResponse(callbackId: callbackId, success: false, data: ["error": error.localizedDescription])
            } else {
                self.sendResponse(callbackId: callbackId, success: true, data: ["completed": completed])
            }
        }
        
        if let popover = activityVC.popoverPresentationController {
            popover.sourceView = view
            popover.sourceRect = CGRect(x: view.bounds.midX, y: view.bounds.midY, width: 0, height: 0)
            popover.permittedArrowDirections = []
        }
        
        present(activityVC, animated: true)
    }
    
    private func sendResponse(callbackId: String?, success: Bool, data: [String: Any]) {
        var response: [String: Any] = [
            "success": success,
            "data": data
        ]
        
        if let callbackId = callbackId {
            response["callbackId"] = callbackId
        }
        
        if let jsonData = try? JSONSerialization.data(withJSONObject: response),
           let jsonString = String(data: jsonData, encoding: .utf8) {
            let script = "window.nativeCallback && window.nativeCallback(\(jsonString));"
            webView.evaluateJavaScript(script)
        }
    }
}

extension WebViewController: WKNavigationDelegate {
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
